mapper.select:
SELECT c.category_id, c.category_name, c.category_code, c.category_description, c.parent_id, c.category_level, c.sort_order, c.is_active, c.enterprise_id, c.creator_id, c.create_time, c.update_by, c.update_time, p.category_name AS parent_name, COUNT(s.script_id) AS script_count, COUNT(child.category_id) AS child_count FROM datacloud_script_category c LEFT JOIN datacloud_script_category p ON c.parent_id = p.category_id LEFT JOIN datacloud_script s ON c.category_id = s.category_id LEFT JOIN datacloud_script_category child ON c.category_id = child.parent_id WHERE c.enterprise_id = #{query.enterpriseId}
AND c.category_name LIKE CONCAT('%', #{query.categoryName}, '%')
AND c.category_code LIKE CONCAT('%', #{query.categoryCode}, '%')
AND c.parent_id = #{query.parentId}
AND c.is_active = #{query.isActive}
GROUP BY c.category_id ORDER BY c.sort_order ASC, c.create_time DESC

SELECT COUNT(*)
FROM datacloud_script_category
WHERE category_code = #{categoryCode}
AND enterprise_id = #{enterpriseId}

    AND category_id != #{excludeId}

SELECT COUNT(*)
FROM datacloud_script
WHERE category_id = #{categoryId}

SELECT COUNT(*)
FROM datacloud_script_category
WHERE parent_id = #{categoryId}

